}

struct TradeResult {
    let success: Bool
    let message: String
}

class PortfolioManager {
    var stocks: [Stock]
    
    func addToPortfolio(stock: Stock) {
        stocks.append(stock)
    }
    
    func removeFromPortfolio(stock: Stock) {
        if let index = stocks.firstIndex(where: { $0.symbol == stock.symbol }) {
            stocks.remove(at: index)
        }
    }
}

