class TradingApp: StockTrading {
    let portfolioManager = PortfolioManager()
    
    func executeTrade(stock: Stock, quantity: Int, action: TradeAction) -> TradeResult {
        let tradeResult = APIManager.shared.executeTradeWithAPI(stock: stock, quantity: quantity, action: action)
        
        if tradeResult.success {
            if action == .buy {
                portfolioManager.addToPortfolio(stock: stock)
            } else if action == .sell {
                portfolioManager.removeFromPortfolio(stock: stock)
